 123→const StickerNode = ({item, stageWidth, stageHeight, isSelected, canEdit, onSelect, onDragEnd, isDraft}) => {
 124→    const emoji = STICKER_OPTIONS[item?.payload?.sticker] || "🐶";
 125→    const image = useEmojiImage(emoji);
 126→    const scale = clamp(Number(item?.payload?.scale) || 1, 0.25, 6);
 127→    const size = clamp(64 * scale, 20, 420);
 128→    const x = clamp((Number(item?.payload?.x) || 0.5) * stageWidth, 0, Math.max(0, stageWidth - size));
 129→    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
 130→    const showBorder = isDraft || isSelected;
 131→
 132→    if(!image){
 133→        return null;
 134→    }
 135→
 136→    return (
 137→        <>
 138→            <KonvaImage
 139→                x={x}
 140→                y={y}
 141→                width={size}
 142→                height={size}
 143→                image={image}
 144→                draggable={canEdit}
 145→                onClick={onSelect}
 146→                onTap={onSelect}
 147→                onDragEnd={onDragEnd}
 148→                rotation={Number(item?.payload?.rotation) || 0}
 149→            />
 150→            {showBorder && (
 151→                <Rect
 152→                    x={x}
 153→                    y={y}
 154→                    width={size}
 155→                    height={size}
 156→                    stroke={isDraft ? "#a21caf" : "#4f46e5"}
 157→                    strokeWidth={2}
 158→                    dash={[6, 4]}
 159→                    listening={false}
 160→                />
 161→            )}
 162→        </>
 163→    );
 164→};
