 218→const NoteNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected, isDraft}) => {
 219→    const payload = item?.payload || {};
 220→    const width = clamp((Number(payload?.width) || 0.26) * stageWidth, 110, stageWidth * 0.9);
 221→    const height = clamp((Number(payload?.height) || 0.2) * stageHeight, 60, stageHeight * 0.8);
 222→    const x = clamp((Number(payload?.x) || 0.45) * stageWidth, 0, Math.max(0, stageWidth - width));
 223→    const y = clamp((Number(payload?.y) || 0.45) * stageHeight, 0, Math.max(0, stageHeight - height));
 224→    const fontStyle = NOTE_STYLE_OPTIONS.includes(payload?.fontStyle) ? payload.fontStyle : "normal";
 225→    const bgColor = payload?.bgColor || "#fff4a8";
 226→    const curlSize = Math.min(width, height) * 0.14;
 227→    const pinSize = Math.max(5, Math.min(width, height) * 0.04);
 228→
 229→    const borderStroke = isDraft ? "#a21caf" : isSelected ? "#a21caf" : "rgba(0,0,0,0.1)";
 230→    const borderWidth = isDraft ? 2 : isSelected ? 2 : 0.5;
 231→    const borderDash = isDraft ? [6, 4] : undefined;
 232→
 233→    return (
 234→        <Group
 235→            x={x}
 236→            y={y}
 237→            draggable={canEdit}
 238→            onDragEnd={onDragEnd}
 239→            onClick={onSelect}
 240→            onTap={onSelect}
 241→            rotation={Number(payload?.rotation) || 0}
 242→        >
 243→            {/* Shadow layer beneath the note */}
 244→            <Shape
 245→                sceneFunc={(ctx, shape) => {
 246→                    ctx.beginPath();
 247→                    ctx.moveTo(2, 4);
 248→                    ctx.lineTo(width + 2, 2);
 249→                    ctx.lineTo(width - curlSize + 4, height + 3);
 250→                    ctx.lineTo(2, height + 2);
 251→                    ctx.closePath();
 252→                    ctx.fillStrokeShape(shape);
 253→                }}
 254→                fill="rgba(0,0,0,0.12)"
 255→                listening={false}
 256→            />
 257→
 258→            {/* Main note body */}
 259→            <Shape
 260→                sceneFunc={(ctx, shape) => {
 261→                    ctx.beginPath();
 262→                    ctx.moveTo(0, 0);
 263→                    ctx.lineTo(width, 0);
 264→                    ctx.lineTo(width, height - curlSize);
 265→                    ctx.lineTo(width - curlSize, height);
 266→                    ctx.lineTo(0, height);
 267→                    ctx.closePath();
 268→                    ctx.fillStrokeShape(shape);
 269→                }}
 270→                fill={bgColor}
 271→                stroke={borderStroke}
 272→                strokeWidth={borderWidth}
 273→                dash={borderDash}
 274→            />
 275→
 276→            {/* Page curl triangle */}
 277→            <Shape
 278→                sceneFunc={(ctx, shape) => {
 279→                    ctx.beginPath();
 280→                    ctx.moveTo(width, height - curlSize);
 281→                    ctx.lineTo(width - curlSize, height - curlSize);
 282→                    ctx.lineTo(width - curlSize, height);
 283→                    ctx.closePath();
 284→                    ctx.fillStrokeShape(shape);
 285→                }}
 286→                fill={darkenColor(bgColor, 0.12)}
 287→                listening={false}
 288→            />
 289→
 290→            {/* Curl fold shadow */}
 291→            <Shape
 292→                sceneFunc={(ctx, shape) => {
 293→                    ctx.beginPath();
 294→                    ctx.moveTo(width - curlSize, height);
 295→                    ctx.lineTo(width, height - curlSize);
 296→                    ctx.lineTo(width - curlSize * 0.55, height - curlSize * 0.55);
 297→                    ctx.closePath();
 298→                    ctx.fillStrokeShape(shape);
 299→                }}
 300→                fill="rgba(0,0,0,0.06)"
 301→                listening={false}
 302→            />
 303→
 304→            {/* Text content */}
 305→            <Text
 306→                x={12}
 307→                y={pinSize * 2 + 10}
 308→                width={width - 24}
 309→                height={height - pinSize * 2 - curlSize - 16}
 310→                text={payload?.text || ""}
 311→                fontFamily={payload?.fontFamily || "Arial"}
 312→                fontStyle={fontStyle}
 313→                fontSize={clamp(Number(payload?.fontSize) || 16, 10, 64)}
 314→                fill={payload?.fontColor || "#1f2937"}
 315→                wrap="word"
 316→                lineHeight={1.3}
 317→            />
 318→
 319→            {/* Left push pin */}
 320→            <Circle x={width * 0.18} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
 321→            <Line points={[width * 0.18, pinSize * 2 + 2, width * 0.18, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
 322→
 323→            {/* Right push pin */}
 324→            <Circle x={width * 0.82} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
 325→            <Line points={[width * 0.82, pinSize * 2 + 2, width * 0.82, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
 326→
 327→            {/* Pin highlights (glossy effect) */}
 328→            <Circle x={width * 0.18 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
 329→            <Circle x={width * 0.82 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
 330→        </Group>
 331→    );
 332→};
