 334→const CURSOR_COLORS = ["#a21caf", "#0ea5e9", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#06b6d4"];
 335→
 336→const getCursorColor = (userId) => {
 337→    let hash = 0;
 338→    const str = String(userId);
 339→    for(let i = 0; i < str.length; i++){
 340→        hash = str.charCodeAt(i) + ((hash << 5) - hash);
 341→    }
 342→    return CURSOR_COLORS[Math.abs(hash) % CURSOR_COLORS.length];
 343→};
