 427→const formatWeekLabel = (week = null) => {
 428→    if(!week?.week_start || !week?.week_end){
 429→        return "No active week";
 430→    }
 431→
 432→    const startDate = new Date(week.week_start);
 433→    const endDate = new Date(week.week_end);
 434→    return `${startDate.toLocaleDateString()} - ${endDate.toLocaleDateString()} (UTC)`;
 435→};
