 437→const isCanvasBackgroundTarget = (target, stage) => {
 438→    if(!target || !stage){
 439→        return false;
 440→    }
 441→
 442→    if(target === stage){
 443→        return true;
 444→    }
 445→
 446→    return target.getParent?.() === stage;
 447→};
