 449→const FreedomWallPage = () => {
 450→    const {session, user, openAuthModal} = useAuth();
 451→    const queryClient = useQueryClient();
 452→    const shellRef = useRef(null);
 453→    const draftDoodleRef = useRef([]);
 454→    const [shellWidth, setShellWidth] = useState(980);
 455→    const [activeTool, setActiveTool] = useState("doodle");
 456→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 457→    const [doodleSize, setDoodleSize] = useState(3.2);
 458→    const [draftDoodlePoints, setDraftDoodlePoints] = useState([]);
 459→    const [isDrawing, setIsDrawing] = useState(false);
 460→    const [selectedSticker, setSelectedSticker] = useState("dog");
 461→    const [wallError, setWallError] = useState(null);
 462→    const [selectedStamp, setSelectedStamp] = useState("heart");
 463→    const [selectedItemId, setSelectedItemId] = useState(null);
 464→    const [draftNote, setDraftNote] = useState(null);
 465→    const [draftSticker, setDraftSticker] = useState(null);
 466→    const [draftStamp, setDraftStamp] = useState(null);
 467→    const [noteEditor, setNoteEditor] = useState({
 468→        text: "",
 469→        fontFamily: "Arial",
 470→        fontStyle: "normal",
 471→        fontColor: "#1f2937",
 472→        bgColor: "#fff4a8",
 473→        fontSize: 16
 474→    });
 475→    const [placementPuffs, setPlacementPuffs] = useState([]);
 476→    const [remoteCursors, setRemoteCursors] = useState({});
 477→    const clientIdRef = useRef(`fw-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
 478→    const realtimeChannelRef = useRef(null);
 479→    const lastCursorBroadcastRef = useRef(0);
 480→
 481→    const authToken = session?.access_token || null;
 482→    const currentUser = user?.userData?.[0] || null;
 483→    const currentUserId = currentUser?.id || null;
 484→    const canWrite = Boolean(currentUserId);
 485→
 486→    const {
 487→        data: activeWeekData,
 488→        isLoading: isWeekLoading,
 489→        error: weekError
 490→    } = useQuery({
 491→        queryKey: ["freedomWallCurrentWeek"],
 492→        queryFn: () => getCurrentFreedomWallWeek(authToken),
 493→        refetchOnWindowFocus: true,
 494→        staleTime: 30 * 1000
 495→    });
 496→
 497→    const activeWeek = activeWeekData?.week || null;
 498→    const weekId = activeWeek?.id || null;
 499→
 500→    const itemsQueryKey = useMemo(() => ["freedomWallItems", weekId], [weekId]);
 501→
 502→    const {
 503→        data: itemsData,
 504→        isLoading: isItemsLoading
 505→    } = useQuery({
 506→        queryKey: itemsQueryKey,
 507→        queryFn: () => getFreedomWallItems(weekId, {limit: 400}, authToken),
 508→        enabled: Boolean(weekId),
 509→        refetchOnWindowFocus: false,
 510→        staleTime: 20 * 1000
 511→    });
 512→
 513→    useEffect(() => {
 514→        const updateShellWidth = () => {
 515→            const nextWidth = shellRef.current?.clientWidth || 980;
 516→            setShellWidth(nextWidth);
 517→        };
 518→
 519→        updateShellWidth();
 520→        window.addEventListener("resize", updateShellWidth);
 521→
 522→        let resizeObserver = null;
 523→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 524→            resizeObserver = new ResizeObserver(updateShellWidth);
 525→            resizeObserver.observe(shellRef.current);
 526→        }
 527→
 528→        return () => {
 529→            window.removeEventListener("resize", updateShellWidth);
 530→            if(resizeObserver){
 531→                resizeObserver.disconnect();
 532→            }
 533→        };
 534→    }, []);
 535→
 536→    const stageWidth = useMemo(() => clamp(shellWidth - 12, 280, WALL_MAX_WIDTH), [shellWidth]);
 537→    const stageHeight = useMemo(() => clamp(Math.round(stageWidth * 0.64), WALL_MIN_HEIGHT, WALL_MAX_HEIGHT), [stageWidth]);
 538→
 539→    const sortedItems = useMemo(() => sortItemsByZIndex(itemsData?.data || []), [itemsData?.data]);
 540→    const maxZIndex = useMemo(() => {
 541→        if(!sortedItems.length){
 542→            return 0;
 543→        }
 544→        return sortedItems.reduce((maxValue, item) => Math.max(maxValue, Number(item?.z_index) || 0), 0);
 545→    }, [sortedItems]);
 546→
 547→    const selectedItem = useMemo(() => {
 548→        if(!selectedItemId){
 549→            return null;
 550→        }
 551→        return sortedItems.find((item) => String(item?.id) === String(selectedItemId)) || null;
 552→    }, [selectedItemId, sortedItems]);
 553→
 554→    const selectedNote = useMemo(() => (
 555→        selectedItem?.item_type === "note" ? selectedItem : null
 556→    ), [selectedItem]);
 557→
 558→    const selectedItemCanEdit = Boolean(selectedItem && currentUserId && String(selectedItem.user_id) === String(currentUserId));
 559→
 560→    useEffect(() => {
 561→        if(!selectedNote){
 562→            return;
 563→        }
 564→
 565→        const payload = selectedNote.payload || {};
 566→        setNoteEditor({
 567→            text: payload.text || "",
 568→            fontFamily: payload.fontFamily || "Arial",
 569→            fontStyle: NOTE_STYLE_OPTIONS.includes(payload.fontStyle) ? payload.fontStyle : "normal",
 570→            fontColor: payload.fontColor || "#1f2937",
 571→            bgColor: payload.bgColor || "#fff4a8",
 572→            fontSize: clamp(Number(payload.fontSize) || 16, 10, 64)
 573→        });
 574→    }, [selectedNote]);
 575→
 576→    useEffect(() => {
 577→        if(activeTool !== "note"){
 578→            setDraftNote(null);
 579→        }
 580→        if(activeTool !== "sticker"){
 581→            setDraftSticker(null);
 582→        }
 583→        if(activeTool !== "stamp"){
 584→            setDraftStamp(null);
 585→        }
 586→    }, [activeTool]);
 587→
 588→    const setItemsCache = useCallback((updater) => {
 589→        if(!weekId){
 590→            return;
 591→        }
